import { isURLSearchParams } from "./url-params";
import type { FacetDetails } from "../types/facet";

export default function replaceHistory(
  currQuery: string,
  currStartRank: number,
  currFacets: { [key: string]: string | string[] },
  currParameters: { [key: string]: string },
  currSort: string,
  facetLabels: FacetDetails[],
  defaultSort: string,
  hasMounted: boolean,
) {
  if (!hasMounted) return;

  const baseParams = new URLSearchParams(window.location.search);

  if (!isURLSearchParams(baseParams)) return;

  // ----- simple params -----
  if (currQuery !== "") {
    baseParams.set("query", currQuery);
  } else {
    baseParams.delete("query");
  }

  if (currStartRank && currStartRank !== 1) {
    baseParams.set("start_rank", currStartRank.toString());
  } else {
    baseParams.delete("start_rank");
  }

  if (currSort !== defaultSort && currSort !== "") {
    baseParams.set("sort", currSort);
  } else {
    baseParams.delete("sort");
  }

  // remove any existing facet params we previously added
  facetLabels.forEach((facet) => {
    if(facet.type === "multiCheckbox"){
      baseParams.delete(`f±${facet.facetName}|${facet.meta}[]`);
    }
    else{
      baseParams.delete(`meta_${facet.meta}_sand`);
    }
  });

  // ----- build facet params manually -----
  let facetQuery = "";
  
  facetLabels.forEach((facet) => {
    const facetValue = currFacets[facet.meta];

    if (!facetValue) return;

    if (Array.isArray(facetValue)) {
      facetValue.forEach((value) => {
        const key = `f±${facet.facetName}|${facet.meta}[]`;
        facetQuery +=
          `&${encodeURIComponent(key)}=` +
          encodeURIComponent(value);
      });
    } else {
      const key = `meta_${facet.meta}_sand`;
      facetQuery +=
        `&${encodeURIComponent(key)}=` +
        encodeURIComponent(facetValue);
    }
  });

  // ----- extra parameters -----
  Object.keys(currParameters).forEach((key) => {
    if (currParameters[key]) {
      baseParams.set(key, currParameters[key]);
    } else {
      baseParams.delete(key);
    }
  });

  const baseString = baseParams.toString();
  const hasParams = baseString.length || facetQuery ? "?" : "";

  window.history.replaceState(
    {},
    "",
    `${window.location.pathname}${hasParams}${baseString}${facetQuery}`,
  );
}
